const input = $input.first().json;

// Handle both flattened and body-nested payloads
const payload = input.body || input;

const csvString = payload.csv_data;
const accountName = payload.account_name || 'Unknown Account';

if (!csvString) {
  throw new Error('No csv_data found in request. Got keys: ' + Object.keys(payload).join(', '));
}

// Parse CSV into array of objects
const lines = csvString.trim().split('\n');
const headers = lines[0].split(',').map(h => h.trim());

const rows = lines.slice(1).map(line => {
  const values = line.split(',').map(v => v.trim());
  const row = {};
  headers.forEach((header, i) => {
    // Convert numeric fields to numbers
    const numericFields = ['impressions', 'clicks', 'cost', 'conversions', 'conv_value', 'quality_score'];
    row[header] = numericFields.includes(header) ? parseFloat(values[i]) || 0 : values[i];
  });
  return row;
});

// Return as a single item with the parsed data
return [{
  json: {
    account_name: accountName,
    row_count: rows.length,
    rows: rows
  }
}];

const data = $input.first().json;
const rows = data.rows;

// Defensive check
if (!rows || rows.length === 0) {
  throw new Error('No rows received from CSV parser. Check upstream node.');
}

// ───────────────────────────────────────────────
// Helper functions
// ───────────────────────────────────────────────

// Sum a numeric field across an array of rows
const sum = (arr, field) => arr.reduce((acc, r) => acc + (r[field] || 0), 0);

// Average a numeric field, ignoring zeros
const avg = (arr, field) => {
  const valid = arr.filter(r => r[field] > 0);
  return valid.length ? sum(valid, field) / valid.length : 0;
};

// Group rows by a field value
const groupBy = (arr, field) => {
  return arr.reduce((acc, row) => {
    const key = row[field] || 'unknown';
    if (!acc[key]) acc[key] = [];
    acc[key].push(row);
    return acc;
  }, {});
};

// Round to 2 decimal places
const round2 = (n) => Math.round(n * 100) / 100;

// Compute aggregated metrics for grouped rows
const computeGroupMetrics = (groupedRows) => {
  return Object.entries(groupedRows).map(([key, items]) => {
    const cost = sum(items, 'cost');
    const conversions = sum(items, 'conversions');
    const clicks = sum(items, 'clicks');
    const impressions = sum(items, 'impressions');
    const conv_value = sum(items, 'conv_value');
    return {
      name: key,
      cost: round2(cost),
      impressions,
      clicks,
      conversions,
      conv_value: round2(conv_value),
      cpa: conversions > 0 ? round2(cost / conversions) : null,
      roas: cost > 0 ? round2(conv_value / cost) : 0,
      ctr: impressions > 0 ? round2((clicks / impressions) * 100) : 0,
      conv_rate: clicks > 0 ? round2((conversions / clicks) * 100) : 0,
      avg_qs: parseFloat(avg(items, 'quality_score').toFixed(1))
    };
  });
};

// ───────────────────────────────────────────────
// Build the metrics object Claude will reason about
// ───────────────────────────────────────────────

const totalSpend = sum(rows, 'cost');
const totalConversions = sum(rows, 'conversions');
const totalClicks = sum(rows, 'clicks');
const totalConvValue = sum(rows, 'conv_value');

const metrics = {
  account_name: data.account_name,
  row_count: rows.length,

  period_summary: {
    total_spend: round2(totalSpend),
    total_clicks: totalClicks,
    total_conversions: totalConversions,
    total_conv_value: round2(totalConvValue),
    overall_cpa: totalConversions > 0 ? round2(totalSpend / totalConversions) : null,
    overall_roas: totalSpend > 0 ? round2(totalConvValue / totalSpend) : 0,
    overall_conv_rate: totalClicks > 0 ? round2((totalConversions / totalClicks) * 100) : 0
  },

  by_campaign: computeGroupMetrics(groupBy(rows, 'campaign')),
  by_match_type: computeGroupMetrics(groupBy(rows, 'match_type')),
  by_device: computeGroupMetrics(groupBy(rows, 'device')),

  // Pre-flagged problem rows for the LLM to reason about
  zero_conv_high_spend: rows
    .filter(r => r.cost > 50 && r.conversions === 0)
    .map(r => ({
      keyword: r.keyword,
      campaign: r.campaign,
      match_type: r.match_type,
      cost: round2(r.cost),
      clicks: r.clicks,
      qs: r.quality_score
    })),

  low_qs_high_spend: rows
    .filter(r => r.quality_score <= 4 && r.cost > 100)
    .map(r => ({
      keyword: r.keyword,
      campaign: r.campaign,
      match_type: r.match_type,
      cost: round2(r.cost),
      qs: r.quality_score
    })),

  top_performers: rows
    .filter(r => r.conversions > 0)
    .sort((a, b) => (a.cost / a.conversions) - (b.cost / b.conversions))
    .slice(0, 5)
    .map(r => ({
      keyword: r.keyword,
      campaign: r.campaign,
      cost: round2(r.cost),
      conversions: r.conversions,
      cpa: round2(r.cost / r.conversions)
    }))
};

return [{ json: metrics }];

const response = $input.first().json;

// Extract the text from Claude's response structure
// Anthropic returns: { content: [{ type: "text", text: "..." }] }
const rawText = response.content[0].text;

// Defensive parsing — strip markdown fences if Claude added them
const cleaned = rawText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

let findings = [];
try {
  findings = JSON.parse(cleaned);
  // Normalize — sometimes Claude returns a single object instead of array
  if (!Array.isArray(findings)) findings = [findings];
} catch (err) {
  // Don't crash — return empty findings with error info for debugging
  return [{
    json: {
      auditor: 'wasted_spend',
      findings: [],
      finding_count: 0,
      parse_error: err.message,
      raw_response: rawText.substring(0, 500) // first 500 chars for debugging
    }
  }];
}

// Also capture token usage — useful for cost tracking
const usage = response.usage || {};

return [{
  json: {
    auditor: 'wasted_spend',
    findings: findings,
    finding_count: findings.length,
    tokens_used: {
      input: usage.input_tokens || 0,
      output: usage.output_tokens || 0
    }
  }
}];

