const response = $input.first().json;
const rawText = response.content[0].text;

const cleaned = rawText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

let prioritizedFindings = [];
try {
  prioritizedFindings = JSON.parse(cleaned);
  if (!Array.isArray(prioritizedFindings)) {
    prioritizedFindings = [prioritizedFindings];
  }

  // Fix zero-indexed ranks if Claude returned 0-9 instead of 1-10
  const minRank = Math.min(...prioritizedFindings.map(f => f.priority_rank));
  if (minRank === 0) {
    prioritizedFindings = prioritizedFindings.map(f => ({
      ...f,
      priority_rank: f.priority_rank + 1
    }));
  }

  // Sort by rank ascending just to be safe
  prioritizedFindings.sort((a, b) => a.priority_rank - b.priority_rank);

} catch (err) {
  return [{
    json: {
      prioritized_findings: [],
      parse_error: err.message,
      raw: rawText.substring(0, 500)
    }
  }];
}

// Pull the account context from the Build Prioritizer Request node
const context = $('Build Prioritizer Request').first().json;

return [{
  json: {
    account_name: context.account_name,
    period_summary: context.period_summary,
    total_findings: context.total_findings,
    severity_breakdown: context.severity_breakdown,
    total_estimated_monthly_savings: context.total_estimated_monthly_savings,
    prioritized_findings: prioritizedFindings,
    top_finding_count: prioritizedFindings.length
  }
}];

const data = $input.first().json;

// Only send top 3 to the report writer — keeps the prompt focused
// and reduces token cost. Full findings are already saved.
const top3 = data.prioritized_findings
  .filter(f => f.priority_rank <= 3);

const systemPrompt = `You are a senior paid media strategist writing an executive audit report for a marketing director.

Write in plain, confident language. No jargon. No hedging. No filler.
The reader is busy. Every sentence must earn its place.

Return ONLY a valid JSON object in this exact structure — no preamble, no markdown fences:

{
  "executive_summary": "3-4 sentences. What is the headline story? What is the single biggest opportunity? What is the total estimated monthly impact if top issues are fixed?",
  "performance_snapshot": "1-2 sentences describing current account health in plain terms using the actual metrics.",
  "top_3_priorities": [
    {
      "rank": 1,
      "title": "short title",
      "action": "specific thing to do this week",
      "impact": "dollar or percentage impact stated plainly"
    }
  ],
  "quick_wins": [
    "Specific action 1 that takes under 1 hour",
    "Specific action 2 that takes under 1 hour",
    "Specific action 3 that takes under 1 hour"
  ],
  "watch_list": [
    "Concern 1 to monitor",
    "Concern 2 to monitor"
  ],
  "audit_metadata": {
    "total_findings": 0,
    "high_severity_count": 0,
    "medium_severity_count": 0,
    "low_severity_count": 0,
    "total_estimated_monthly_savings": 0
  }
}`;

const userMessage = 
  "Write the executive audit report for this account.\n\n" +
  "Account: " + data.account_name + "\n\n" +
  "Period Metrics:\n" + JSON.stringify(data.period_summary, null, 2) + "\n\n" +
  "Finding Summary:\n" +
  "- Total findings: " + data.total_findings + "\n" +
  "- Severity breakdown: " + JSON.stringify(data.severity_breakdown) + "\n" +
  "- Total estimated monthly savings: $" + data.total_estimated_monthly_savings + "\n\n" +
  "Top 3 Priority Findings:\n" + JSON.stringify(top3, null, 2);

const requestBody = {
  model: "claude-opus-4-5",
  max_tokens: 4096,
  system: systemPrompt,
  messages: [{ role: "user", content: userMessage }]
};

return [{
  json: {
    request_body: JSON.stringify(requestBody),
    // Pass context through for the final assembly
    account_name: data.account_name,
    period_summary: data.period_summary,
    prioritized_findings: data.prioritized_findings,
    total_findings: data.total_findings,
    severity_breakdown: data.severity_breakdown,
    total_estimated_monthly_savings: data.total_estimated_monthly_savings
  }
}];

const response = $input.first().json;
const rawText = response.content[0].text;

// Clean markdown fences if present
const cleaned = rawText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

let report = {};
try {
  report = JSON.parse(cleaned);

  // Fill audit_metadata from actual data if Claude left zeros
  const context = $('Build Report Writer Request').first().json;
  if (report.audit_metadata) {
    report.audit_metadata.total_findings = context.total_findings;
    report.audit_metadata.total_estimated_monthly_savings = 
      context.total_estimated_monthly_savings;
    report.audit_metadata.high_severity_count = 
      context.severity_breakdown?.high || 0;
    report.audit_metadata.medium_severity_count = 
      context.severity_breakdown?.medium || 0;
    report.audit_metadata.low_severity_count = 
      context.severity_breakdown?.low || 0;
  }

} catch (err) {
  report = {
    executive_summary: "Report generation failed.",
    parse_error: err.message,
    raw: rawText.substring(0, 500)
  };
}

const context = $('Build Report Writer Request').first().json;

return [{
  json: {
    account_name: context.account_name,
    period_summary: context.period_summary,
    report: report,
    prioritized_findings: context.prioritized_findings,
    total_findings: context.total_findings,
    severity_breakdown: context.severity_breakdown,
    total_estimated_monthly_savings: context.total_estimated_monthly_savings
  }
}];
